<script setup lang="ts">
import { computed } from 'vue'
import { Coupon, ServiceTypeLabel, DiscountType, CommissionType } from '../types'
import { useFormat } from '../../../composables/useFormat'

const props = defineProps<{
    coupon: Coupon | null
}>()

defineEmits<{
    (event: 'delete', coupon: Coupon): void
}>()

const { formatDate } = useFormat()

const serviceTypeLabels = computed(() => {
    if (!props.coupon?.serviceDetails?.length) return '-'
    return props.coupon.serviceDetails.map((sd) => ServiceTypeLabel[sd.serviceType] || sd.serviceType).join('、')
})

const discountRules = computed(() => {
    if (!props.coupon?.serviceDetails?.length) return []
    return props.coupon.serviceDetails.map((sd) => ({
        serviceType: ServiceTypeLabel[sd.serviceType] || sd.serviceType,
        rule:
            sd.discountType === DiscountType.Percentage ? `折扣 ${sd.discountValue}%` : `折扣 NT$ ${sd.discountValue}`,
    }))
})

const commissionRules = computed(() => {
    if (!props.coupon?.serviceDetails?.length) return []
    return props.coupon.serviceDetails.map((sd) => ({
        serviceType: ServiceTypeLabel[sd.serviceType] || sd.serviceType,
        rule:
            sd.commissionType === CommissionType.Percentage
                ? `佣金 ${sd.commissionValue}%`
                : `佣金 NT$ ${sd.commissionValue}`,
    }))
})

const statusInfo = computed(() => {
    if (!props.coupon) return { label: '-', color: 'secondary' }
    const now = Date.now()
    const start = Number(props.coupon.startTimestamp)
    const end = Number(props.coupon.endTimestamp)

    if (end && end < now) return { label: '已過期', color: 'secondary' }
    if (start > now) return { label: '未開始', color: 'info' }
    return { label: '啟用中', color: 'success' }
})

const promoUrl = computed(() => {
    if (!props.coupon) return ''
    return `https://vnhappy7.com/?coupon=${props.coupon.code}`
})

const copyPromoUrl = () => {
    navigator.clipboard.writeText(promoUrl.value)
}

const validityPeriod = computed(() => {
    if (!props.coupon) return '-'
    const start = formatDate(Number(props.coupon.startTimestamp))
    const end = Number(props.coupon.endTimestamp) ? formatDate(Number(props.coupon.endTimestamp)) : '無結束日期'
    return `${start} ~ ${end}`
})
</script>

<template>
    <div v-if="coupon" class="flex flex-col gap-4">
        <div class="grid grid-cols-2 gap-y-3 gap-x-4">
            <div class="text-sm text-gray-500">優惠碼</div>
            <div class="font-semibold">{{ coupon.code }}</div>

            <div class="text-sm text-gray-500">推廣夥伴</div>
            <div>{{ coupon.promoterName }}</div>

            <div class="text-sm text-gray-500">訂單類型</div>
            <div>{{ serviceTypeLabels }}</div>

            <div class="text-sm text-gray-500">狀態</div>
            <div>
                <VaBadge :text="statusInfo.label" :color="statusInfo.color" />
            </div>

            <div class="text-sm text-gray-500">有效期限</div>
            <div>{{ validityPeriod }}</div>
        </div>

        <div v-if="discountRules.length" class="mt-2">
            <div class="text-sm text-gray-500 mb-1">折扣規則</div>
            <div v-for="r in discountRules" :key="r.serviceType" class="pl-2 text-sm">
                {{ r.serviceType }}：{{ r.rule }}
            </div>
        </div>

        <div v-if="commissionRules.length" class="mt-2">
            <div class="text-sm text-gray-500 mb-1">佣金規則</div>
            <div v-for="r in commissionRules" :key="r.serviceType" class="pl-2 text-sm">
                {{ r.serviceType }}：{{ r.rule }}
            </div>
        </div>

        <div class="mt-2">
            <div class="text-sm text-gray-500 mb-1">推廣網址</div>
            <div class="flex items-center gap-2">
                <span class="text-sm break-all">{{ promoUrl }}</span>
                <VaButton
                    preset="secondary"
                    size="small"
                    icon="content_copy"
                    aria-label="複製推廣網址"
                    @click="copyPromoUrl"
                />
                <VaButton
                    preset="secondary"
                    size="small"
                    icon="open_in_new"
                    aria-label="開啟推廣網址"
                    :href="promoUrl"
                    target="_blank"
                    tag="a"
                />
            </div>
        </div>

        <div class="flex justify-end mt-4">
            <VaButton color="danger" @click="$emit('delete', coupon)"> 刪除優惠碼 </VaButton>
        </div>
    </div>
</template>
