<script setup lang="ts">
import { ref } from 'vue'
import { useRouter } from 'vue-router'
import CouponsTable from './widgets/CouponsTable.vue'
import CouponDetailModal from './widgets/CouponDetailModal.vue'
import { Coupon, ServiceType, ServiceTypeLabel } from './types'
import { useCoupons } from './composables/useCoupons'
import { useModal, useToast } from 'vuestic-ui'

const router = useRouter()
const { coupons, isLoading, filters, pagination, promoters, ...couponsApi } = useCoupons()

// --- Detail Modal ---
const showDetailModal = ref(false)
const selectedCoupon = ref<Coupon | null>(null)

const onViewCoupon = async (coupon: Coupon) => {
    const detail = await couponsApi.getCouponDetail(coupon.id)
    selectedCoupon.value = detail
    showDetailModal.value = true
}

// --- Delete ---
const { confirm } = useModal()
const { init: notify } = useToast()

const onDeleteCoupon = async (coupon: Coupon) => {
    const agreed = await confirm({
        title: '刪除優惠碼',
        message: `確定要刪除優惠碼「${coupon.code}」嗎？此操作無法復原。`,
        okText: '刪除',
        cancelText: '取消',
        size: 'small',
        maxWidth: '380px',
    })

    if (agreed) {
        try {
            await couponsApi.remove(coupon.id)
            showDetailModal.value = false
            notify({ message: '優惠碼已刪除', color: 'success' })
        } catch (error) {
            notify({ message: '刪除失敗，請再試一次', color: 'danger' })
        }
    }
}

// --- Filter options ---
const promoterFilterOptions = [{ value: '' as const, text: '全部推廣夥伴' }]

const serviceTypeFilterOptions = [
    { value: '', text: '全部訂單類型' },
    ...Object.values(ServiceType).map((st) => ({
        value: st,
        text: ServiceTypeLabel[st],
    })),
]

const goToAddCoupon = () => {
    router.push({ name: 'coupons-add' })
}
</script>

<template>
    <h1 class="page-title">優惠碼管理</h1>

    <VaCard>
        <VaCardContent>
            <div class="flex flex-col md:flex-row gap-2 mb-4 justify-between">
                <div class="flex flex-col md:flex-row gap-2 justify-start">
                    <VaSelect
                        v-model="filters.promoterId"
                        :options="[
                            ...promoterFilterOptions,
                            ...promoters.map((p) => ({ value: p.id, text: p.userName || `Promoter #${p.id}` })),
                        ]"
                        value-by="value"
                        text-by="text"
                        placeholder="全部推廣夥伴"
                        class="w-48"
                    />
                    <VaSelect
                        v-model="filters.serviceType"
                        :options="serviceTypeFilterOptions"
                        value-by="value"
                        text-by="text"
                        placeholder="全部訂單類型"
                        class="w-48"
                    />
                </div>
                <VaButton @click="goToAddCoupon">新增優惠碼</VaButton>
            </div>

            <CouponsTable :coupons="coupons" :loading="isLoading" :pagination="pagination" @viewCoupon="onViewCoupon" />
        </VaCardContent>
    </VaCard>

    <VaModal v-model="showDetailModal" size="small" mobile-fullscreen close-button hide-default-actions>
        <h1 class="va-h5 mb-4">優惠碼詳細資訊</h1>
        <CouponDetailModal :coupon="selectedCoupon" @delete="onDeleteCoupon" />
    </VaModal>
</template>
