<script setup lang="ts">
import { defineVaDataTableColumns } from 'vuestic-ui'
import { Coupon, ServiceTypeLabel, DiscountType, CommissionType } from '../types'
import { PropType, computed, toRef } from 'vue'
import { Pagination } from '../composables/useCoupons'

const columns = defineVaDataTableColumns([
    { label: '優惠碼', key: 'code', sortable: true },
    { label: '推廣夥伴', key: 'promoterName', sortable: true },
    { label: '訂單類型', key: 'serviceTypes' },
    { label: '折扣規則', key: 'discountRule' },
    { label: '佣金規則', key: 'commissionRule' },
    { label: '狀態', key: 'status' },
])

const props = defineProps({
    coupons: {
        type: Array as PropType<Coupon[]>,
        required: true,
    },
    loading: { type: Boolean, default: false },
    pagination: { type: Object as PropType<Pagination>, required: true },
})

const emit = defineEmits<{
    (event: 'viewCoupon', coupon: Coupon): void
}>()

const coupons = toRef(props, 'coupons')
const totalPages = computed(() => Math.ceil(props.pagination.total / props.pagination.perPage))

const getServiceTypeLabels = (coupon: Coupon): string => {
    if (!coupon.serviceDetails?.length) return '-'
    return coupon.serviceDetails.map((sd) => ServiceTypeLabel[sd.serviceType] || sd.serviceType).join('、')
}

const getDiscountRule = (coupon: Coupon): string => {
    if (!coupon.serviceDetails?.length) return '-'
    const first = coupon.serviceDetails[0]
    if (first.discountType === DiscountType.Percentage) {
        return `折扣 ${first.discountValue}%`
    }
    return `折扣 NT$ ${first.discountValue}`
}

const getCommissionRule = (coupon: Coupon): string => {
    if (!coupon.serviceDetails?.length) return '-'
    const first = coupon.serviceDetails[0]
    if (first.commissionType === CommissionType.Percentage) {
        return `佣金 ${first.commissionValue}%`
    }
    return `佣金 NT$ ${first.commissionValue}`
}

const getCouponStatus = (coupon: Coupon): { label: string; color: string } => {
    const now = Date.now()
    const start = Number(coupon.startTimestamp)
    const end = Number(coupon.endTimestamp)

    if (end && end < now) {
        return { label: '已過期', color: 'secondary' }
    }
    if (start > now) {
        return { label: '未開始', color: 'info' }
    }
    return { label: '啟用中', color: 'success' }
}
</script>

<template>
    <VaDataTable :columns="columns" :items="coupons" :loading="$props.loading">
        <template #cell(code)="{ rowData }">
            <a
                class="text-primary font-semibold cursor-pointer hover:underline"
                @click="emit('viewCoupon', rowData as Coupon)"
            >
                {{ rowData.code }}
            </a>
        </template>

        <template #cell(promoterName)="{ rowData }">
            <div class="ellipsis max-w-[180px]">{{ rowData.promoterName }}</div>
        </template>

        <template #cell(serviceTypes)="{ rowData }">
            <div class="max-w-[200px]">{{ getServiceTypeLabels(rowData as Coupon) }}</div>
        </template>

        <template #cell(discountRule)="{ rowData }">
            {{ getDiscountRule(rowData as Coupon) }}
        </template>

        <template #cell(commissionRule)="{ rowData }">
            {{ getCommissionRule(rowData as Coupon) }}
        </template>

        <template #cell(status)="{ rowData }">
            <VaBadge
                :text="getCouponStatus(rowData as Coupon).label"
                :color="getCouponStatus(rowData as Coupon).color"
            />
        </template>
    </VaDataTable>

    <div class="flex flex-col-reverse md:flex-row gap-2 justify-between items-center py-2">
        <div>
            <b>{{ $props.pagination.total }} results.</b>
            Results per page
            <VaSelect v-model="$props.pagination.perPage" class="!w-20" :options="[10, 50, 100]" />
        </div>

        <div v-if="totalPages > 1" class="flex">
            <VaButton
                preset="secondary"
                icon="va-arrow-left"
                aria-label="Previous page"
                :disabled="$props.pagination.page === 1"
                @click="$props.pagination.page--"
            />
            <VaButton
                class="mr-2"
                preset="secondary"
                icon="va-arrow-right"
                aria-label="Next page"
                :disabled="$props.pagination.page === totalPages"
                @click="$props.pagination.page++"
            />
            <VaPagination
                v-model="$props.pagination.page"
                buttons-preset="secondary"
                :pages="totalPages"
                :visible-pages="5"
                :boundary-links="false"
                :direction-links="false"
            />
        </div>
    </div>
</template>
